import React from 'react';

const DetailProduk = () => {
  return (
    <div style={{ padding: '20px' }}>
      <h2>Halaman Detail Produk</h2>
      <p>Informasi detail mengenai kue akan ditampilkan di sini.</p>
    </div>
  );
};

export default DetailProduk;
